import react, { useState, useMemo } from 'react';

const records = [
    { id: 1, name: 'adam', age: 25 },
    { id: 2, name: 'james', age: 30 },
    { id: 3, name: 'nick', age: 28 },
    { id: 4, name: 'john', age: 29 }
];

const sortabletable = () => {
    const [filtertext, setfiltertext] = useState('');
    const [sortconfig, setsortconfig] = useState({ key: null, direction: 'asc' });

    // efficient filtering and sorting using useMemo to prevent recalculation on every render
    const processeddata = useMemo(() => {
        let result = records.filter(record => {
            const lowername = record.name.toLowerCase();
            const lowerfilter = filtertext.toLowerCase();
            return lowername.includes(lowerfilter);
        });

        if (sortconfig.key) {
            result.sort((a, b) => {
                if (a[sortconfig.key] < b[sortconfig.key]) {
                    return sortconfig.direction === 'asc' ? -1 : 1;
                }
                if (a[sortconfig.key] > b[sortconfig.key]) {
                    return sortconfig.direction === 'asc' ? 1 : -1;
                }
                return 0;
            });
        }

        return result;
    }, [filtertext, sortconfig]);

    const handleclick = (key) => {
        setsortconfig(prev => ({
            key: key,
            direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
        }));
    };

    const getsortindicator = (key) => {
        if (sortconfig.key !== key) return '';
        return sortconfig.direction === 'asc' ? ' ↑' : ' ↓';
    };

    return (
        <div style={{ fontFamily: 'sans-serif', padding: '20px' }}>
            <h2>performant data table</h2>
            <input
                type="text"
                placeholder="filter by name..."
                value={filtertext}
                onChange={(e) => setfiltertext(e.target.value)}
